class Solution:
    def findBall(self, grid):
        m = len(grid)
        n = len(grid[0])
        result = []
        for start in range(n):
            col = start
            stuck = False
            for row in range(m):
                d = grid[row][col]
                nc = col + d
                if nc < 0 or nc >= n:
                    stuck = True
                    break
                if grid[row][nc] != d:
                    stuck = True
                    break
                col = nc
            result.append(-1 if stuck else col)
        return result

