var findBall = function(grid) {
    const m = grid.length;
    const n = m ? grid[0].length : 0;
    const answer = [];
    for (let start = 0; start < n; start++) {
        let col = start;
        for (let row = 0; row < m; row++) {
            const d = grid[row][col];
            const nc = col + d;
            if (nc < 0 || nc >= n || grid[row][nc] !== d) {
                col = -1;
                break;
            }
            col = nc;
        }
        answer.push(col);
    }
    return answer;
};
